        root_hobt.ClientAppointmentReceived,
	root_hobt.AppointedFromStageId,
        root_hobt.BillingInstruction,
        root_hobt.CannotBeInvoiced,
	root_hobt.CannotBeInvoicedReason,
        root_hobt.AgentContractID,
